-- ============================================================================
-- 174_processing_template_suite_v2.sql
-- ----------------------------------------------------------------------------
-- UI-simplification lane: upgrade the four ACTIVE default templates to the v2
-- simplified suite. v2 removes the six retired display fields (Farm, Planned
-- Processing Date (SF), Actual/Planned Time On Farm, Time Remaining Until
-- Processing, Product Pick-up Date) and makes Customer a SINGLE select sourced
-- from settings.customer_options (like Processor). Broiler carries 11 fields;
-- cattle/pig/sheep carry 10.
--
-- Contract (Codex-gated):
--   * FAIL CLOSED: a program upgrades ONLY when its active template's fields
--     are byte-for-byte (jsonb-equal) the known default v1 that mig 172 seeded.
--     Anything else — an administrator customized it — RAISES and (under
--     psql --single-transaction) rolls the whole migration back.
--   * IDEMPOTENT: an active template already carrying the v2 fields is a no-op.
--   * CHECKLIST PRESERVED: the new v2 version carries the ACTIVE template's
--     checklist VERBATIM (admin re-pointing of step assignees survives). Only
--     when a program has no active template at all (fresh environment with the
--     seed removed) is the canonical default checklist used.
--   * NEVER deletes template rows or touches processing_records — stored field
--     values (including values of retired fields) are kept.
--
-- The v2 JSON below is the CANONICAL suite from src/lib/processingFields.js
-- defaultProcessingTemplateSuite(); the static guard
-- processing_template_suite_static.test.js asserts equality both ways
-- (174 v2 == JS suite; 174 expected-v1 == 172 seed) so nothing can drift.
-- created_by reuses the importer actor helper (first admin) — service/psql
-- applies have no auth.uid(). Error class: PROCESSING_VALIDATION:.
-- NO BEGIN/COMMIT (TEST via exec_sql; PROD via psql --single-transaction).
-- Depends on: 156 (templates table), 162 (customer_options), 164
-- (_processing_import_actor), 172 (v1 seed).
-- ============================================================================

DO $mig$
DECLARE
  v_program   text;
  v_v1        jsonb;
  v_v2        jsonb;
  v_checklist jsonb;
  v_expected  int;
  v_active    public.processing_templates;
BEGIN
  FOREACH v_program IN ARRAY ARRAY['broiler','cattle','pig','sheep'] LOOP
    v_v1 :=
      CASE v_program WHEN 'broiler' THEN '[{"id":"procActual","name":"Actual Processing Date (SF)","type":"date"},{"id":"status","name":"Status (Processing)","type":"single","options":[{"key":"planned","label":"Planned","color":{"bg":"#E8B73E","ink":"#5A4304"}},{"key":"reserved","label":"Reserved","color":{"bg":"#93C896","ink":"#285F33"}},{"key":"in_proccess","label":"In-Proccess","color":{"bg":"#E4924A","ink":"#6F3711"}},{"key":"completed","label":"Completed","color":{"bg":"#E07A6E","ink":"#6E1C15"}},{"key":"tbc","label":"TBC","color":{"bg":"#E59CC0","ink":"#6F2A50"}},{"key":"goal","label":"Goal","color":{"bg":"#6AA6DD","ink":"#173B5E"}}]},{"id":"program","name":"Farm Programs","type":"single","options":[{"key":"broiler","label":"Broiler","color":{"bg":"#E8B73E","ink":"#5A4304"}},{"key":"cattle","label":"Cattle","color":{"bg":"#F0B3A8","ink":"#9F3322"}},{"key":"pig","label":"Pigs","color":{"bg":"#6AA6DD","ink":"#173B5E"}},{"key":"sheep","label":"Lambs","color":{"bg":"#93C896","ink":"#285F33"}}]},{"id":"batchName","name":"Batch Name (Farms)","type":"text"},{"id":"farm","name":"Farm","type":"single","options":[{"key":"wcf","label":"WCF","color":{"bg":"#DDF1EE","ink":"#2E7A73"}}]},{"id":"animals","name":"Animals Processed","type":"number"},{"id":"condemned","name":"Condemed","type":"number"},{"id":"farmArrival","name":"Farm Arrival Date","type":"date"},{"id":"year","name":"Year","type":"single","options":[{"key":"y2026","label":"2026","color":{"bg":"#EDEFF1","ink":"#5B626C"}},{"key":"y2027","label":"2027","color":{"bg":"#EDEFF1","ink":"#5B626C"}}]},{"id":"animalMaster","name":"Status (Animal Master)","type":"single","options":[{"key":"scheduled","label":"Scheduled","color":{"bg":"#EDEFF1","ink":"#5B626C"}},{"key":"on_farm","label":"On Farm","color":{"bg":"#E7EDF8","ink":"#3B6CB7"}},{"key":"inventoried","label":"Inventoried","color":{"bg":"#DDF1EE","ink":"#2E7A73"}}]},{"id":"procPlanned","name":"Planned Processing Date (SF)","type":"date"},{"id":"actualTOF","name":"Actual Time On Farm","type":"formula"},{"id":"plannedTOF","name":"Planned Time on Farm","type":"formula"},{"id":"timeRemaining","name":"Time Remaining Until Processing","type":"formula"},{"id":"productPickup","name":"Product Pick-up Date","type":"date"},{"id":"customer","name":"Customer (Broiler)","type":"multi","options":[{"key":"sonnys","label":"Sonny''s","color":{"bg":"#BFE3CB","ink":"#245737"}},{"key":"coastal_confirmed","label":"Coastal Pastures - CONFIRMED","color":{"bg":"#F0B3A8","ink":"#9F3322"}},{"key":"coastal_potential","label":"Coastal Pastures - POTENTIAL","color":{"bg":"#EFC07E","ink":"#875213"}}]},{"id":"processor","name":"Processor","type":"single","optionsSource":"settings.processor_options"}]'::jsonb
