           WHEN 'cattle' THEN '[{"label":"Send Weight & Animal Count","assignee":"Ronnie Jones","assignee_profile_id":null},{"label":"Prepare Cut List","assignee":"Ronnie Jones","assignee_profile_id":null},{"label":"Create and Post Inventory Intake Sheet","assignee":"Brett Post","assignee_profile_id":null},{"label":"Determine Wholesale Price / Animal","assignee":"Brett Post","assignee_profile_id":null},{"label":"Add to Processing Spreadsheet by Protein","assignee":"Brett Post","assignee_profile_id":null},{"label":"Create Invoice from Farm to Customer","assignee":"Brett Post","assignee_profile_id":null},{"label":"Obtain Product List from Processor & Send to Debbie","assignee":"Isabel Hermann","assignee_profile_id":null},{"label":"Inventory in Product & Send to Debbie","assignee":"Isabel Hermann","assignee_profile_id":null},{"label":"If Applicable - Send photo of new product label to Debbie","assignee":"Isabel Hermann","assignee_profile_id":null},{"label":"Add Inventory to Shopify","assignee":"Jessica Torres","assignee_profile_id":null},{"label":"Reconcile and Analyze Podio","assignee":"Ronnie Jones","assignee_profile_id":null},{"label":"Prepare Cutlist for Processor","assignee":"Ronnie Jones","assignee_profile_id":null},{"label":"Approve Cutlist","assignee":"Isabel Hermann","assignee_profile_id":null},{"label":"Inventory in Product through Asana Inventory Form","assignee":"Jessica Torres","assignee_profile_id":null},{"label":"Schedule/Notify payment of Kill & Processing","assignee":"Ronnie Jones","assignee_profile_id":null},{"label":"Update Status to Inventoried","assignee":"Jessica Torres","assignee_profile_id":null}]'::jsonb
           WHEN 'pig' THEN '[{"label":"Send Weight & Animal Count","assignee":"Ronnie Jones","assignee_profile_id":null},{"label":"Prepare Cut List","assignee":"Ronnie Jones","assignee_profile_id":null},{"label":"Add to Processing Spreadsheet by Protein","assignee":"Brett Post","assignee_profile_id":null},{"label":"Create Invoice from Farm to Customer","assignee":"Brett Post","assignee_profile_id":null},{"label":"Inventory in Product and add to Asana","assignee":"Isabel Hermann","assignee_profile_id":null},{"label":"If Applicable - Send photo of new product label","assignee":"Isabel Hermann","assignee_profile_id":null},{"label":"Add Inventory to Shopify","assignee":"Jessica Torres","assignee_profile_id":null},{"label":"Reconcile and Analyze Podio","assignee":"Ronnie Jones","assignee_profile_id":null},{"label":"Inventory in Product through Asana Inventory Form","assignee":"Jessica Torres","assignee_profile_id":null},{"label":"If Applicable - Send photo of new product label to Debbie","assignee":"Isabel Hermann","assignee_profile_id":null},{"label":"Update Status to Inventoried","assignee":"Jessica Torres","assignee_profile_id":null}]'::jsonb
           WHEN 'sheep' THEN '[{"label":"Send Weight & Animal Count","assignee":"Ronnie Jones","assignee_profile_id":null},{"label":"Prepare Cut List","assignee":"Ronnie Jones","assignee_profile_id":null},{"label":"Add to Processing Spreadsheet by Protein","assignee":"Brett Post","assignee_profile_id":null},{"label":"Create Invoice from Farm to Customer","assignee":"Brett Post","assignee_profile_id":null},{"label":"Inventory in Product and add to Asana","assignee":"Isabel Hermann","assignee_profile_id":null},{"label":"If Applicable - Send photo of new product label","assignee":"Isabel Hermann","assignee_profile_id":null},{"label":"Add Inventory to Shopify","assignee":"Jessica Torres","assignee_profile_id":null},{"label":"Reconcile and Analyze Podio","assignee":"Ronnie Jones","assignee_profile_id":null},{"label":"Update Final Animal Count & Weight","assignee":"Ronnie Jones","assignee_profile_id":null},{"label":"Schedule/Notify payment of Kill & Processing with Jennifer","assignee":"Ronnie Jones","assignee_profile_id":null},{"label":"Obtain Product List from Processor & Save to Egnyte","assignee":"Isabel Hermann","assignee_profile_id":null},{"label":"Inventory in Product through Asana Inventory Form","assignee":"Jessica Torres","assignee_profile_id":null},{"label":"If Applicable - Send photo of new product label to Debbie","assignee":"Isabel Hermann","assignee_profile_id":null},{"label":"Approve Cutlist","assignee":"Isabel Hermann","assignee_profile_id":null},{"label":"Prepare Cutlist for Processor","assignee":"Ronnie Jones","assignee_profile_id":null},{"label":"Update Status to Inventoried","assignee":"Jessica Torres","assignee_profile_id":null}]'::jsonb
      END;
    v_expected := CASE v_program WHEN 'broiler' THEN 11 ELSE 10 END;

    IF jsonb_array_length(v_v2) <> v_expected THEN
      RAISE EXCEPTION 'PROCESSING_VALIDATION: v2 % template must carry exactly % fields (found %)',
        v_program, v_expected, jsonb_array_length(v_v2);
    END IF;

    SELECT * INTO v_active
      FROM public.processing_templates
     WHERE program = v_program AND is_active = true;

    IF NOT FOUND THEN
      -- Fresh environment with no active template: seed v2 directly with the
      -- canonical default checklist.
      INSERT INTO public.processing_templates (id, program, version, fields, checklist, is_active, created_by)
      VALUES ('ptpl-default-' || v_program || '-v2', v_program,
              COALESCE((SELECT max(version) FROM public.processing_templates WHERE program = v_program), 0) + 1,
              v_v2, v_checklist, true, public._processing_import_actor());
      CONTINUE;
    END IF;

    IF v_active.fields = v_v2 THEN
      CONTINUE; -- already upgraded — reapplication is a no-op
    END IF;

    IF v_active.fields IS DISTINCT FROM v_v1 THEN
      RAISE EXCEPTION 'PROCESSING_VALIDATION: active % template (v%) was administrator-customized — refusing the automatic v2 upgrade; publish the change from the Templates manager instead',
        v_program, v_active.version;
    END IF;

    -- Known default v1 -> supersede with v2, preserving the checklist VERBATIM.
    UPDATE public.processing_templates SET is_active = false WHERE id = v_active.id;
    INSERT INTO public.processing_templates (id, program, version, fields, checklist, is_active, created_by)
    VALUES ('ptpl-default-' || v_program || '-v2', v_program, v_active.version + 1,
            v_v2, v_active.checklist, true, public._processing_import_actor());
  END LOOP;
END
$mig$;
